// ===================== EDITE AQUI =====================
const CONFIG = {
  evoUrl: 'https://SUA-EVOLUTION-API',                 // base URL da sua Evolution API (sem barra no fim)
  evoInstance: 'arkai',                                // nome da instância na Evolution
  evoApiKey: 'COLE_SUA_APIKEY',                        // apikey da Evolution
  renanNumber: '5521979610875',                        // WhatsApp do Renan para handoff (só números)
  leadWebhook: 'https://nwook.futurosolaroficial.cloud/webhook/Arkai - Leads - Site',
  bookingUrl: 'https://calendly.com/arkaisolutions',
};
// =====================================================

const b = $input.first().json.body || $input.first().json;
const data = (b && b.data) || {};
const key = data.key || {};
const remoteJid = key.remoteJid || '';
const fromMe = key.fromMe || false;
const isGroup = remoteJid.endsWith('@g.us');
const msg = data.message || {};
const text = msg.conversation
  || (msg.extendedTextMessage && msg.extendedTextMessage.text)
  || (msg.imageMessage && msg.imageMessage.caption)
  || '';

// Ignora mensagens próprias, de grupos e vazias
if (fromMe || isGroup || !text) { return []; }

// Detecta intenção de lead quente (handoff para o Renan)
const hot = /(pre[çc]o|valor|quanto custa|proposta|contrato|fechar|come[çc]ar|contratar|falar com|humano|atendente)/i.test(text);

return [{ json: { ...CONFIG, number: remoteJid, name: data.pushName || '', text, hot } }];
